<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">-k,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --keep</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">        # 保留（不要删除）输入文件</span></span>
